const assert = require("node:assert/strict");

const timeoutArg = process.argv.find((arg) => arg.startsWith("--testTimeout="));
const timeoutMs = timeoutArg ? Number(timeoutArg.split("=")[1]) : 50;

function slowOperation() {
  return new Promise((resolve) => setTimeout(() => resolve("done"), 60));
}

async function runTest(name, fn) {
  let timer;
  const timeout = new Promise((_, reject) => {
    timer = setTimeout(() => {
      reject(
        new Error(
          `Exceeded timeout of ${timeoutMs} ms for a test. Use jest.setTimeout(newTimeout) or run with --testTimeout=<ms>.`
        )
      );
    }, timeoutMs);
  });

  try {
    await Promise.race([fn(), timeout]);
    clearTimeout(timer);
    console.log(`ok - ${name}`);
  } catch (error) {
    clearTimeout(timer);
    console.error(error.message);
    process.exitCode = 1;
  }
}

runTest("slow operation finishes", async () => {
  assert.equal(await slowOperation(), "done");
});

const { Readable, Writable } = require('node:stream');
const { pipeline } = require('node:stream/promises');

const DEFAULT_TIMEOUT_MS = 50;
const STREAM_DELAY_MS = 120;

function delayedReadable(delayMs) {
  let started = false;
  return new Readable({
    read() {
      if (started) {
        return;
      }

      started = true;
      setTimeout(() => {
        this.push('ok');
        this.push(null);
      }, delayMs);
    },
  });
}

async function readSlowStream(timeoutMs = DEFAULT_TIMEOUT_MS) {
  let output = '';
  const sink = new Writable({
    write(chunk, encoding, callback) {
      output += chunk.toString();
      callback();
    },
  });

  try {
    await pipeline(delayedReadable(STREAM_DELAY_MS), sink, {
      signal: AbortSignal.timeout(timeoutMs),
    });
  } catch (error) {
    if (error.name === 'AbortError') {
      throw new Error(`operation timed out after ${timeoutMs}ms`, {
        cause: error,
      });
    }

    throw error;
  }

  return output;
}

module.exports = { readSlowStream };

const assert = require('node:assert/strict');
const { readSlowStream } = require('./runner');

(async () => {
  const output = await readSlowStream();
  assert.equal(output, 'ok');
})();

